import{_ as p,C as e,o as i,c as l,j as s,a as t,E as r,ag as h}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"11. 图数据库：面向关系网络 / 知识图谱 / 路径分析的数据系统","description":"理解节点、边、路径、多跳查询、知识图谱和 GraphRAG 在数据平台中的位置。","frontmatter":{"title":"11. 图数据库：面向关系网络 / 知识图谱 / 路径分析的数据系统","description":"理解节点、边、路径、多跳查询、知识图谱和 GraphRAG 在数据平台中的位置。","prev":{"text":"10. 向量数据库：面向 AI / RAG / 语义检索的数据系统","link":"/chapters/10-vector-databases"},"next":{"text":"12. 数据湖与湖仓架构","link":"/chapters/12-lakehouse"}},"headers":[],"relativePath":"chapters/11-graph-databases.md","filePath":"chapters/11-graph-databases.md"}'),c={name:"chapters/11-graph-databases.md"};function d(o,a,b,u,m,g){const n=e("Mermaid");return i(),l("div",null,[a[0]||(a[0]=s("h1",{id:"_11-图数据库-面向关系网络-知识图谱-路径分析的数据系统",tabindex:"-1"},[t("11. 图数据库：面向关系网络 / 知识图谱 / 路径分析的数据系统 "),s("a",{class:"header-anchor",href:"#_11-图数据库-面向关系网络-知识图谱-路径分析的数据系统","aria-label":'Permalink to "11. 图数据库：面向关系网络 / 知识图谱 / 路径分析的数据系统"'},"​")],-1)),a[1]||(a[1]=s("div",{class:"tip custom-block"},[s("p",{class:"custom-block-title"},"本章导读"),s("p",null,"理解节点、边、路径、多跳查询、知识图谱和 GraphRAG 在数据平台中的位置。")],-1)),r(n,{code:"flowchart%20LR%0A%20%20U%5B%22User%22%5D%20--%3E%7CPURCHASED%7C%20P%5B%22Product%22%5D%0A%20%20P%20--%3E%7CBELONGS_TO%7C%20C%5B%22Category%22%5D%0A%20%20D%5B%22Document%22%5D%20--%3E%7CMENTIONS%7C%20E%5B%22Entity%22%5D%0A%20%20E%20--%3E%7CRELATED_TO%7C%20E2%5B%22Entity%22%5D%0A%20%20E2%20--%3E%20G%5B%22GraphRAG%20Context%22%5D%0A"}),a[2]||(a[2]=h(`<p>关系型数据库也能表达关系。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>但当问题重点从“记录本身”转向“记录之间的多跳关系、路径和网络结构”时，图数据库会更自然。</p><p>第 10 章讨论了向量数据库，它擅长根据语义相似性召回内容。但很多业务问题不是“哪个文本更相似”，而是“这些实体之间如何连接”：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>某个用户和欺诈团伙之间隔了几层关系？</span></span>
<span class="line"><span>一个供应商风险会影响哪些下游订单和客户？</span></span>
<span class="line"><span>一篇文档提到的实体与哪些政策、产品、负责人相关？</span></span>
<span class="line"><span>两个客户是否通过手机号、设备、地址或交易网络间接关联？</span></span>
<span class="line"><span>GraphRAG 中应该沿哪些实体关系扩展上下文？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这些问题如果只用关系型数据库表达，通常会变成多张表的递归 JOIN、复杂路径查询和难以维护的关系逻辑。图数据库出现的原因，就是让关系网络本身成为可以建模、查询和分析的对象。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p>图数据库不是为了替代关系型数据库，而是为复杂关系、多跳查询和网络分析提供更直接的数据模型。</p></blockquote><p>本章要建立的判断是：图数据库解决的是实体关系、路径、多跳查询和网络结构分析问题。它让“关系”不只是外键或 JOIN 条件，而是可以带方向、属性、权重、路径和算法的核心数据。</p><p>图数据库也不是所有关系问题的最佳解。简单主外键、事务写入、报表聚合和指标分析仍然更适合关系数据库、数仓和 OLAP。图数据库应该用于关系网络本身成为分析对象的场景。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="_11-1-基础概念" tabindex="-1">11.1 基础概念 <a class="header-anchor" href="#_11-1-基础概念" aria-label="Permalink to &quot;11.1 基础概念&quot;">​</a></h3><p>图由节点和边组成。</p><p>Node / Vertex 表示实体。</p><p>Edge / Relationship 表示实体之间的关系。</p><p>Property 表示节点或边的属性。</p><p>Label 表示节点类别。</p><p>Path 表示从一个节点经过若干边到另一个节点的路径。</p><p>Graph 是整体关系网络。</p><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(User)-[:PURCHASED]-&gt;(Product)</span></span>
<span class="line"><span>(User)-[:VIEWED]-&gt;(Product)</span></span>
<span class="line"><span>(Company)-[:OWNS]-&gt;(Company)</span></span>
<span class="line"><span>(Document)-[:MENTIONS]-&gt;(Entity)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>图模型的核心判断是：</p><blockquote><p>当关系本身成为查询对象时，图比表更直接。</p></blockquote><h3 id="_11-2-图数据模型" tabindex="-1">11.2 图数据模型 <a class="header-anchor" href="#_11-2-图数据模型" aria-label="Permalink to &quot;11.2 图数据模型&quot;">​</a></h3><p>常见图模型包括 Property Graph 和 RDF Graph。</p><p>Property Graph 中，节点和边都可以有属性。</p><p>RDF Graph 用三元组表达：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>subject -&gt; predicate -&gt; object</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>知识图谱通常围绕实体、关系、属性、本体和 schema 构建。</p><p>Entity 是实体，例如用户、公司、产品、疾病、论文。</p><p>Relation 是实体之间的关系，例如购买、任职、投资、引用。</p><p>Ontology 是概念体系，定义实体类型、关系类型和约束。</p><p>图建模的关键不是把所有东西都画成点和线，而是明确：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>什么是节点？</span></span>
<span class="line"><span>什么是边？</span></span>
<span class="line"><span>边是否有方向？</span></span>
<span class="line"><span>边是否有权重？</span></span>
<span class="line"><span>哪些属性放节点？</span></span>
<span class="line"><span>哪些属性放边？</span></span>
<span class="line"><span>查询需要几跳？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="_11-3-查询语言" tabindex="-1">11.3 查询语言 <a class="header-anchor" href="#_11-3-查询语言" aria-label="Permalink to &quot;11.3 查询语言&quot;">​</a></h3><p>常见图查询语言包括：</p><ul><li>Cypher。</li><li>Gremlin。</li><li>SPARQL。</li><li>GQL。</li><li>openCypher。</li></ul><p>Cypher 查询示例：</p><div class="language-cypher vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cypher</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">MATCH</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (u:User)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">[:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">PURCHASED</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(p:Product)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> u.user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;501&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RETURN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> p.name;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>多跳查询示例：</p><div class="language-cypher vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cypher</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">MATCH</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (a:Company)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">[:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">OWNS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*1..3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(b:Company)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a.name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;A 公司&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RETURN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b.name;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>SQL 可以通过多表 JOIN 表达关系，但多跳路径查询会越来越复杂。</p><p>图查询更关注模式匹配、路径、邻居、连通性和子图。</p><h3 id="_11-4-图数据库产品" tabindex="-1">11.4 图数据库产品 <a class="header-anchor" href="#_11-4-图数据库产品" aria-label="Permalink to &quot;11.4 图数据库产品&quot;">​</a></h3><p>常见图数据库包括：</p><ul><li>Neo4j。</li><li>NebulaGraph。</li><li>JanusGraph。</li><li>TigerGraph。</li><li>ArangoDB。</li><li>Amazon Neptune。</li><li>HugeGraph。</li><li>Memgraph。</li><li>PostgreSQL + Apache AGE。</li></ul><p>不同产品边界不同。</p><p>Neo4j 生态成熟，适合知识图谱、路径查询和应用开发。</p><p>NebulaGraph 更关注分布式大规模图。</p><p>JanusGraph 常结合外部存储和索引系统。</p><p>Amazon Neptune 支持图云服务。</p><p>Apache AGE 让 PostgreSQL 获得图查询扩展能力。</p><h3 id="_11-5-图算法" tabindex="-1">11.5 图算法 <a class="header-anchor" href="#_11-5-图算法" aria-label="Permalink to &quot;11.5 图算法&quot;">​</a></h3><p>图数据库不只查询路径，也可以支持图算法。</p><p>常见算法包括：</p><ul><li>BFS。</li><li>DFS。</li><li>Shortest Path。</li><li>PageRank。</li><li>Community Detection。</li><li>Connected Components。</li><li>Centrality。</li><li>Similarity。</li><li>Graph Embedding。</li></ul><p>这些算法解决的是网络结构问题。</p><p>例如：</p><ul><li>最短路径用于供应链路径、关系链路、知识跳转。</li><li>PageRank 衡量节点重要性。</li><li>社区发现识别关系群体。</li><li>连通分量发现团伙或孤立网络。</li><li>Graph Embedding 把图结构转成向量，用于推荐或 GraphRAG。</li></ul><h3 id="_11-6-知识图谱" tabindex="-1">11.6 知识图谱 <a class="header-anchor" href="#_11-6-知识图谱" aria-label="Permalink to &quot;11.6 知识图谱&quot;">​</a></h3><p>知识图谱通常包括：</p><ul><li>实体抽取。</li><li>关系抽取。</li><li>实体消歧。</li><li>实体对齐。</li><li>本体设计。</li><li>三元组构建。</li><li>图谱存储。</li><li>图谱推理。</li><li>图谱问答。</li><li>GraphRAG。</li></ul><p>知识图谱不是“把文本丢进图数据库”。</p><p>它需要先定义实体类型、关系类型和抽取规则，再把文档、业务表、日志和外部知识转成可查询图结构。</p><p>GraphRAG 把图结构引入 RAG，让检索不只依赖语义相似，也能沿实体关系扩展上下文。</p><h3 id="_11-7-图数据库在大数据体系中的位置" tabindex="-1">11.7 图数据库在大数据体系中的位置 <a class="header-anchor" href="#_11-7-图数据库在大数据体系中的位置" aria-label="Permalink to &quot;11.7 图数据库在大数据体系中的位置&quot;">​</a></h3><p>图数据库的数据可以来自：</p><ul><li>PostgreSQL 业务表。</li><li>数仓事实表和维度表。</li><li>日志和事件流。</li><li>文档解析结果。</li><li>实体抽取和关系抽取。</li></ul><p>典型链路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL / 文档 / 日志</span></span>
<span class="line"><span>  -&gt; 实体抽取</span></span>
<span class="line"><span>  -&gt; 关系抽取</span></span>
<span class="line"><span>  -&gt; 图数据库</span></span>
<span class="line"><span>  -&gt; 路径查询 / 图算法 / GraphRAG</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>图数据库常与 Spark GraphX / GraphFrames 做离线图计算，与 Kafka / Flink 处理实时关系更新，与向量数据库结合做 GraphRAG。</p><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>图数据库是 AI 数据基础设施和数据平台中的关系网络层。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL 业务表 / 数仓事实表 / 文档 / 日志</span></span>
<span class="line"><span>  -&gt; 实体抽取 / 关系抽取 / ID 对齐</span></span>
<span class="line"><span>  -&gt; Graph DB</span></span>
<span class="line"><span>  -&gt; 路径查询 / 图算法 / 知识图谱 / GraphRAG</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>它和前后系统的关系很明确：</p><ul><li>PostgreSQL 和数仓提供结构化事实来源。</li><li>文档解析和信息抽取提供非结构化实体关系。</li><li>向量数据库提供语义相似召回。</li><li>图数据库提供显式关系扩展和路径约束。</li><li>数据治理负责实体口径、关系质量、权限和血缘。</li></ul><p>图数据库引出第 12 章湖仓：结构化表、文档、图谱、向量和日志都会产生大量原始数据和中间产物，需要一个开放、低成本、可被多引擎访问的数据底座。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>以企业知识库 GraphRAG 为例，向量检索可以找到和问题相似的段落，但它未必知道这些段落中提到的实体之间是什么关系。</p><p>可以构建一张知识图谱：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(Document)-[:MENTIONS]-&gt;(Policy)</span></span>
<span class="line"><span>(Policy)-[:APPLIES_TO]-&gt;(Department)</span></span>
<span class="line"><span>(Policy)-[:OWNED_BY]-&gt;(Person)</span></span>
<span class="line"><span>(Product)-[:HAS_RISK]-&gt;(Risk)</span></span>
<span class="line"><span>(Risk)-[:MITIGATED_BY]-&gt;(Policy)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>当用户问“这个产品上线前需要遵守哪些安全要求？”时，系统可以：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 用向量检索召回相关产品文档。</span></span>
<span class="line"><span>2. 抽取产品、风险、政策、安全要求等实体。</span></span>
<span class="line"><span>3. 沿图关系查找 Product -&gt; Risk -&gt; Policy -&gt; Owner。</span></span>
<span class="line"><span>4. 把相关政策、负责人、适用部门和原文片段组装进上下文。</span></span>
<span class="line"><span>5. 让 LLM 生成带来源的回答。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这个案例体现图数据库的价值：它不是替代向量检索，而是把“相似内容”扩展成“有关系约束的上下文网络”。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：图数据库比关系型数据库更适合所有关系。</strong></p><p>简单外键关系和事务查询，关系型数据库更直接。图数据库适合多跳、路径和网络结构问题。</p><p><strong>误区二：知识图谱就是图数据库。</strong></p><p>图数据库是存储和查询系统，知识图谱还包括本体、抽取、消歧、对齐、质量和应用。</p><p><strong>误区三：把表直接转成节点和边就是图建模。</strong></p><p>图建模要围绕查询问题决定节点、边和属性，不是机械转换。</p><p><strong>误区四：图数据库上了以后就自动有知识图谱。</strong></p><p>知识图谱还需要实体抽取、关系抽取、本体设计、消歧、对齐、质量评估和应用闭环。图数据库只是存储和查询层。</p><p><strong>误区五：GraphRAG 可以只靠图，不需要向量。</strong></p><p>图关系适合显式路径和实体扩展，向量检索适合语义召回。高质量 GraphRAG 通常需要两者协同。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>设计一个电商关系图：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User</span></span>
<span class="line"><span>Product</span></span>
<span class="line"><span>Order</span></span>
<span class="line"><span>Category</span></span>
<span class="line"><span>Brand</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>关系包括：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User PURCHASED Product</span></span>
<span class="line"><span>Product BELONGS_TO Category</span></span>
<span class="line"><span>Product HAS_BRAND Brand</span></span>
<span class="line"><span>User VIEWED Product</span></span>
<span class="line"><span>User SIMILAR_TO User</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>要求：</p><ul><li>定义节点属性。</li><li>定义边属性。</li><li>写出 3 个路径查询问题。</li><li>判断哪些数据来自 PostgreSQL，哪些来自事件日志。</li><li>说明这个图如何服务推荐或 GraphRAG。</li></ul><p>补充要求：</p><ul><li>写出一个 2 跳查询、一个 3 跳查询和一个最短路径查询。</li><li>说明 <code>Order</code> 是否应该作为节点，还是只作为 <code>PURCHASED</code> 边上的属性。</li><li>设计一个实体去重规则，例如同一用户多个设备、手机号或邮箱如何对齐。</li><li>说明哪些图数据可以离线批量构建，哪些关系需要实时更新。</li><li>说明图谱结果如何与向量检索结果合并进入 GraphRAG 上下文。</li></ul><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>图数据库让关系网络成为一等查询对象。</p><p>它适合多跳关系、路径分析、知识图谱、风控、推荐和 GraphRAG。</p><p>下一章进入数据湖与湖仓。</p><p>因为结构化表、日志、文档、向量和图谱背后，都需要一个能长期存储、组织和被多引擎访问的数据底座。</p>`,109))])}const y=p(c,[["render",d]]);export{v as __pageData,y as default};
